#include<cstdio>
#include<vector>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=6e4+10,BK=256;
int head[N],des[N<<1],nxt[N<<1],cgt,n,Sz,lst,a[N];
inline void ins(const int &x,const int &y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;
}
namespace Block
{
	int V[N],B[N],loc[N],L[N],R[N],blk;
	inline void Build()
	{
		rep(1,Sz,i)loc[i]=(i-1)/BK+1;blk=Sz/BK;
		rep(1,blk,i)L[i]=R[i-1]+1,R[i]=i*BK;
		if(blk*BK!=Sz){++blk;L[blk]=R[blk-1]+1;R[blk]=n;}
		memcpy(B,V,(Sz+3)<<2);
		rep(1,blk,i)std::sort(B+L[i],B+R[i]+1);
	}
	inline void mdy(const int &x,const int &w)
	{
		int k=loc[x];V[x]=w;rep(L[k],R[k],i)B[i]=V[i];
		std::sort(B+L[k],B+R[k]+1);
	}
	inline int bnd(const int &bk,const int &k)
	{
		int l=L[bk],r=R[bk],res=-1,mid;
		while(l<=r)B[mid=(l+r)>>1]<=k?l=mid+1:(r=mid-1,res=mid);
		return ~res?R[bk]-res+1:0;
	}
	inline int qry(const int &l,const int &r,const int &k)
	{
		if(loc[l]==loc[r]){int ans=0;rep(l,r,i)if(V[i]>k)++ans;return ans;}
		int ans=0,ql=loc[l],qr=loc[r];rep(l,R[ql],i)ans+=(V[i]>k);rep(L[qr],r,i)ans+=(V[i]>k);
		for(int i=ql+1;i<qr;++i)ans+=bnd(i,k);return ans;
	}
}
namespace Seg
{
	std::vector<int> OP[N<<2],res;int idx[N];
	inline void Init(const int &l=1,const int &r=60000,const int &cur=1)
	{
		OP[cur].clear();if(l==r){idx[l]=cur;return;};
		int mid=(l+r)>>1;Init(l,mid,cur<<1);Init(mid+1,r,cur<<1|1);
	}
	inline void add(const int &ql,const int &qr,const int &w,const int &l=1,const int &r=60000,const int &cur=1)
	{
//		printf("%d %d %d %d\n",l,r,ql,qr);
//		if(cur==1)printf("add %d %d\n",ql,qr);
		if(ql<=l&&r<=qr){OP[cur].push_back(w);return;} const int &mid=(l+r)>>1;
		if(ql<=mid)add(ql,qr,w,l,mid,cur<<1);if(qr>mid)add(ql,qr,w,mid+1,r,cur<<1|1);
	}
	inline int qry(const int &x,const int &k)
	{
		res.clear();int p=idx[x],res=0;
		while(p){for(int v:OP[p])res+=(a[v]>k);p=p>>1;} return res;
	}
}
namespace TreeCut
{
	int siz[N],dep[N],ql[N],qr[N],top[N],mxs[N],fa[N],cdt;
	inline void dfs1(const int &u=1,const int &f=0)
	{
		siz[u]=1;int mx=0;dep[u]=dep[fa[u]=f]+1;
		grep(u,i)if(des[i]!=f){int v=des[i];dfs1(v,u);siz[u]+=siz[v];mx<siz[v]?mx=siz[mxs[u]=v]:0;}
	}
	inline void dfs2(const int &u=1,const int &fa=0,const int &tp=1)
	{
		Block::V[ql[u]=++cdt]=a[u];top[u]=tp;if(mxs[u])dfs2(mxs[u],u,tp);
		grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs2(des[i],u,des[i]);qr[u]=cdt;
	}
	inline void Build(){cdt=0;dfs1();dfs2();Sz=n;Seg::Init();Block::Build();}
	inline void Add(int f,int w)
	{
		fa[++n]=f;a[n]=w;top[n]=n;ins(n,f);ql[n]=++cdt;
		int x=n;while(x){Seg::add(ql[top[x]],ql[x],n);x=fa[top[x]];}
	}
	inline void Mdy(int x,int w){a[x]=w;if(x<=Sz)Block::mdy(ql[x],w);}
	inline void Qry(int x,int k)
	{
		int ans=(x<=Sz?Block::qry(ql[x],qr[x],k):0);
//		printf("Qry :: %d -> ",ans);
		ans+=Seg::qry(ql[x],k);printf("%d\n",lst=ans);
	}
}
using TreeCut::Add; using TreeCut::Mdy;using TreeCut::Qry;
inline void debug()
{
	puts("DE");rep(1,n,u)grep(u,i)printf("%d %d\n",u,des[i]);puts("DE");
}
int main()
{
//	FIN("data.in");
	n=read();rep(2,n,i)ins(read(),read());
	rep(1,n,i)a[i]=read();TreeCut::Build();
//	puts("QAQ");
	int Q=read(),x;while(Q--)
	{
		switch(read())
		{
			case 0:x=read()^lst;Qry(x,read()^lst);break;
			case 1:x=read()^lst;Mdy(x,read()^lst);break;
			case 2:x=read()^lst;Add(x,read()^lst);break;
		}
		if(n-Sz>256)TreeCut::Build();
	}
//	debug();rep(1,n,i)printf("%d ",a[i]);puts("");
}
